% Display nicely
%for k = 1:numel(theory)
    %if theory(k) ~= 0
        %fprintf('Stat %d: theory = %.4g, sim = %.4g, discrepancy = %.3f%%n', ...
               % k, theory(k), sim(k), pct(k));
